const { chromium } = require('./node_modules/playwright/index.mjs');
(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:18800');
  const ctx = browser.contexts()[0];
  const page = ctx.pages()[0];

  console.log('Current URL:', page.url());

  // Find and fill email
  const emailInput = await page.locator('input');
  let emailFilled = false;
  for (const input of await emailInput.all()) {
    const type = await input.getAttribute('type');
    const placeholder = await input.getAttribute('placeholder') || '';
    const ariaLabel = await input.getAttribute('aria-label') || '';
    if (type === 'email' || placeholder.includes('email') || ariaLabel.includes('email')) {
      await input.fill('samwilkiedevs@gmail.com');
      console.log('Email filled');
      emailFilled = true;
      break;
    }
  }

  if (!emailFilled) {
    // Try clicking first and typing
    await page.locator('input').first().click();
    await page.waitForTimeout(300);
    await page.keyboard.type('samwilkiedevs@gmail.com');
