      name: i.name,
      placeholder: i.placeholder,
      id: i.id,
      className: i.className.substring(0, 80)
    }));
  });
  console.log('All inputs:', JSON.stringify(inputs, null, 2));

  // Get all divs/spans that contain numbers 1-6 (tab numbers)
  const tabs = await page.evaluate(() => {
    const all = document.querySelectorAll('div, span, li, a');
