      .filter(el => {
        const text = el.innerText.trim();
        return text === '1' || text === '2' || text === '3' || text === '4' || text === '5' || text === '6' ||
               text === 'Overview' || text === 'Pricing' || text === 'Description & FAQ' ||
               text === 'Requirements' || text === 'Gallery' || text === 'Publish';
      })
      .map(el => ({
        text: el.innerText.trim(),
        className: el.className.substring(0, 80),
        tagName: el.tagName
      }));
  });
  console.log('Tabs/navigation:', JSON.stringify(tabs, null, 2));

  await page.screenshot({ path: '/tmp/fiverr_inspect.png', fullPage: false });
